describe('usePhotoPreviewGestures', () => {
  let mockTranslateX: { value: number };
  let mockDragOffset: { value: number };
  let mockCurrentIndex: { value: number };
  let mockRotationY: { value: number };
  const mockPrepareTransition = jest.fn();
  const mockFinalizeTransition = jest.fn();
  let mockIsTransitioning: { value: boolean };

  beforeAll(() => {
    originalTiming = reanimatedModule.withTiming;
    originalSpring = reanimatedModule.withSpring;
    originalDecay = reanimatedModule.withDecay;
    originalUseSharedValue = reanimatedModule.useSharedValue;

    (reanimatedModule as any).withTiming = (value: any, config: any, callback: any) => {
      if (typeof callback === 'function') callback(true);
      return value;
    };

    (reanimatedModule as any).withSpring = (value: any, config: any, callback: any) => {
      if (typeof callback === 'function') callback(true);
      return value;
    };

    (reanimatedModule as any).withDecay = (config: any, callback: any) => {
      if (typeof callback === 'function') callback(true);
      return config.velocity > 0 ? 100 : -100;
    };

    (reanimatedModule as any).useSharedValue = (val: any) => {
      return { value: val };
    };
  });

  afterAll(() => {
    (reanimatedModule as any).withTiming = originalTiming;
    (reanimatedModule as any).withSpring = originalSpring;
    (reanimatedModule as any).withDecay = originalDecay;
    (reanimatedModule as any).useSharedValue = originalUseSharedValue;
  });

  beforeEach(() => {
    jest.clearAllMocks();
    mockTranslateX = { value: 0 };
    mockDragOffset = { value: 0 };
    mockCurrentIndex = { value: 0 };
    mockRotationY = { value: 0 };
    mockIsTransitioning = { value: false };
  });

  const getHookResult = () => {
    return renderHook(() =>
      usePhotoPreviewGestures({
        width: 400,
        height: 800,
        photosLength: 3,
        slotWidth: 400,
        translateX: mockTranslateX as any,
        dragOffset: mockDragOffset as any,
        currentIndex: mockCurrentIndex as any,
        rotationY: mockRotationY as any,
        selectedPhoto: { id: '1', uri: 'file:///test/1.jpg' },
        prepareTransition: mockPrepareTransition,
        finalizeTransition: mockFinalizeTransition,
        isTransitioning: mockIsTransitioning as any,
      })
    );
  };

  it('initializes gestures with standard values', () => {
    const { result } = getHookResult();

    expect(result.current.zoomScale.value).toBe(1);
    expect(result.current.zoomTranslateX.value).toBe(0);
    expect(result.current.zoomTranslateY.value).toBe(0);
    expect(result.current.isZoomed.value).toBe(false);
  });

  it('handles double tap to zoom in', () => {
    const { result } = getHookResult();

    expect(capturedDoubleTapCallbacks.onEnd).toBeDefined();

    act(() => {
      // Simulate double tap on coordinates x=150, y=300
      capturedDoubleTapCallbacks.onEnd({ x: 150, y: 300 });
    });

    expect(result.current.isZoomed.value).toBe(true);
    expect(result.current.zoomScale.value).toBe(2.5);
    // centerX=200, targetX = (200 - 150) * 1.5 = 75
    expect(result.current.zoomTranslateX.value).toBe(75);
    // centerY=400, targetY = (400 - 300) * 1.5 = 150
    expect(result.current.zoomTranslateY.value).toBe(150);
  });

  it('does not zoom on double tap if transition is in progress', () => {
    const { result } = getHookResult();
    mockIsTransitioning.value = true;

    act(() => {
      capturedDoubleTapCallbacks.onEnd({ x: 150, y: 300 });
    });

    expect(result.current.isZoomed.value).toBe(false);
    expect(result.current.zoomScale.value).toBe(1);
  });

  it('handles double tap to zoom out when already zoomed', () => {
    const { result } = getHookResult();

    // Zoom in first
    act(() => {
      capturedDoubleTapCallbacks.onEnd({ x: 200, y: 400 });
    });
    expect(result.current.isZoomed.value).toBe(true);

    // Zoom out
    act(() => {
      capturedDoubleTapCallbacks.onEnd({ x: 200, y: 400 });
    });

    expect(result.current.isZoomed.value).toBe(false);
    expect(result.current.zoomScale.value).toBe(1);
    expect(result.current.zoomTranslateX.value).toBe(0);
    expect(result.current.zoomTranslateY.value).toBe(0);
  });

  it('handles pinch gesture update and end', () => {
    const { result } = getHookResult();

    expect(capturedPinchCallbacks.onUpdate).toBeDefined();
    expect(capturedPinchCallbacks.onEnd).toBeDefined();

    // Scale up via pinch
    act(() => {
      capturedPinchCallbacks.onUpdate({ scale: 2 });
    });

    expect(result.current.zoomScale.value).toBe(2);
    expect(result.current.isZoomed.value).toBe(true);

    // Scale down to < 1.1 and end (resets zoom)
    act(() => {
      capturedPinchCallbacks.onUpdate({ scale: 0.5 }); // 2 * 0.5 = 1.0 (but bounded minimum 1)
      capturedPinchCallbacks.onEnd();
    });

    expect(result.current.isZoomed.value).toBe(false);
    expect(result.current.zoomScale.value).toBe(1);
  });

  it('handles pan gesture (swipe mode) when not zoomed', () => {
    const { result } = getHookResult();

    expect(capturedPanCallbacks.onStart).toBeDefined();
    expect(capturedPanCallbacks.onUpdate).toBeDefined();
    expect(capturedPanCallbacks.onEnd).toBeDefined();

    // Start swipe
    act(() => {
      capturedPanCallbacks.onStart({ translationX: 0 });
    });
    expect(mockDragOffset.value).toBe(0);

    // Update (drag to negative x)
    act(() => {
      capturedPanCallbacks.onUpdate({ translationX: -250 });
    });
    expect(mockTranslateX.value).toBe(-250);

    // End (release exceeding half width threshold - width is 400)
    act(() => {
      capturedPanCallbacks.onEnd({ velocityX: -600 });
    });

    expect(mockTranslateX.value).toBe(-400); // target index 1 * slotWidth
    expect(mockFinalizeTransition).toHaveBeenCalledWith(1, true);
  });

  it('handles pan gesture (pan mode) when zoomed', () => {
    const { result } = getHookResult();

    // Zoom in
    act(() => {
      capturedDoubleTapCallbacks.onEnd({ x: 200, y: 400 });
    });

    // Start pan
    act(() => {
      capturedPanCallbacks.onStart();
    });

    // Move pan
    act(() => {
      capturedPanCallbacks.onUpdate({ translationX: 50, translationY: -50 });
    });

    // Confirm that coordinates shift in pan mode
    expect(result.current.zoomTranslateX.value).toBeGreaterThan(0);
    expect(result.current.zoomTranslateY.value).toBeLessThan(0);

    // End pan (should trigger decay)
    act(() => {
      capturedPanCallbacks.onEnd({ velocityX: 100, velocityY: -100 });
    });

    // Expect zoom values to change due to simulated withDecay
    expect(result.current.zoomTranslateX.value).toBeDefined();
    expect(result.current.zoomTranslateY.value).toBeDefined();
  });
});

import { useEffect } from 'react';
import { AppState } from 'react-native';
import { useGalleryStore } from '@entities/gallery';
import { useShallow } from 'zustand/shallow';
import * as MediaLibrary from 'expo-media-library/legacy';
import { logger } from '@shared/lib/logger';

export const useRecentMediaThumbnail = () => {
  const { setLatestCapturedUri } = useGalleryStore(useShallow(state => ({
    setLatestCapturedUri: state.setLatestCapturedUri,
  })));

  useEffect(() => {
    const loadInitialThumbnail = async () => {
      try {
        const perms = await MediaLibrary.getPermissionsAsync();
        if (perms.granted || perms.status === ('limited' as any)) {
          const allAlbums = await MediaLibrary.getAlbumsAsync();
          const grovkornetAlbums = allAlbums.filter(a => a.title.toLowerCase() === 'grovkornet');

          let foundUri: string | null = null;
          let foundFilename: string | null = null;
          let foundId: string | null = null;

          if (grovkornetAlbums.length > 0) {
            const fetchPromises = grovkornetAlbums.map(album => 
              MediaLibrary.getAssetsAsync({
                album: album.id,
                first: 1,
                sortBy: [[MediaLibrary.SortBy.creationTime, false]],
                mediaType: MediaLibrary.MediaType.photo,
              })
            );
            
            const results = await Promise.all(fetchPromises);
            const combinedAssets = results.flatMap(r => r.assets);
            combinedAssets.sort((a, b) => b.creationTime - a.creationTime);
            
            if (combinedAssets.length > 0) {
              foundUri = combinedAssets[0].uri;
              foundFilename = combinedAssets[0].filename;
              foundId = combinedAssets[0].id;
            }
          }
          
          if (!foundUri) {
            const recent = await MediaLibrary.getAssetsAsync({
              first: 200,
              sortBy: [[MediaLibrary.SortBy.creationTime, false]],
              mediaType: MediaLibrary.MediaType.photo,
            });
            
            const latestGrovkornet = recent.assets.find(a => 
              a.uri.includes('Grovkornet') || 
              a.filename.includes('Grovkornet') || 
              a.filename.startsWith('Grovkornet_') ||
              a.filename.startsWith('GVK_')
            );
            
            if (latestGrovkornet) {
              foundUri = latestGrovkornet.uri;
              foundFilename = latestGrovkornet.filename;
              foundId = latestGrovkornet.id;
            }
          }

          if (foundUri) {
            const currentUri = useGalleryStore.getState().latestCapturedUri;
            
            // Prevent state updates and UI flickers if it's the exact same file
            if (currentUri === foundUri) return;
            if (currentUri && foundFilename && currentUri.includes(foundFilename)) return;
            if (currentUri && foundId && currentUri.endsWith(foundId)) return;

            setLatestCapturedUri(foundUri);
          }
        }
      } catch (e) {
        logger.warn('useRecentMediaThumbnail', 'Failed to load initial thumbnail', e);
      }
    };

    void loadInitialThumbnail();

    const subscription = AppState.addEventListener('change', nextAppState => {
      if (nextAppState === 'active') {
        void loadInitialThumbnail();
      }
    });

    return () => {
      subscription.remove();
    };
  }, [setLatestCapturedUri]);
};

import React, { memo } from 'react';
import { StyleSheet, useWindowDimensions } from 'react-native';
import Animated, { useAnimatedStyle, SharedValue } from 'react-native-reanimated';
import { Image } from 'expo-image';
import { GalleryItem } from '../../lib/types';

interface AnimatedSlotProps {
  photo: GalleryItem;
  index: number;
  translateX: SharedValue<number>;
  slotWidth: number;
  gap: number;
  rotationY?: SharedValue<number>;
  zoomScale?: SharedValue<number>;
  zoomTranslateX?: SharedValue<number>;
  zoomTranslateY?: SharedValue<number>;
  currentIndex?: SharedValue<number>;
  onLoad?: () => void;
  initialUri?: string | null;
}

export const AnimatedSlot = memo(({
  photo,
  index,
  translateX,
  slotWidth,
  gap,
  rotationY,
  zoomScale,
  zoomTranslateX,
  zoomTranslateY,
  currentIndex,
  onLoad,
  initialUri,
}: AnimatedSlotProps) => {
  const { width: screenW, height: screenH } = useWindowDimensions();

  // Keep track of the previous URI to use it as a placeholder when migrating from preview to final URI
  const previousUriRef = React.useRef<string>(photo.uri);
  const previousIdRef = React.useRef<string>(photo.id);
  const placeholderUriRef = React.useRef<string | undefined>(undefined);

  if (photo.uri !== previousUriRef.current) {
    // Only use the previous URI as a placeholder if it's the SAME photo (e.g., thumbnail -> high-res).
    // If it's a completely different photo (teleport), clear the placeholder so we don't flash the wrong image.
    if (photo.id === previousIdRef.current) {
      placeholderUriRef.current = previousUriRef.current;
    } else {
      placeholderUriRef.current = undefined;
    }
    previousUriRef.current = photo.uri;
    previousIdRef.current = photo.id;
  }

  const outerStyle = useAnimatedStyle(() => {
    const currentX = index * slotWidth + translateX.value;
    const isFocused = Math.abs(currentX) < slotWidth / 2;
    
    const angle = rotationY ? rotationY.value : 0;
    const normalizedAngle = Math.abs(angle % 90);
    const isRotating = normalizedAngle > 1 && normalizedAngle < 89;

    return {
      transform: [{ translateX: currentX }],
      zIndex: isFocused ? 10 : 0,
      opacity: (!isFocused && isRotating) ? 0 : 1,
    };
  });

  const zoomStyle = useAnimatedStyle(() => {
    if (!zoomScale || !zoomTranslateX || !zoomTranslateY || !currentIndex) {
      return {};
    }
    const isActive = index === currentIndex.value;
    if (!isActive) {
      return {};
    }
    return {
      transform: [
        { translateX: zoomTranslateX.value },
        { translateY: zoomTranslateY.value },
        { scale: zoomScale.value },
      ],
    };
  });

  const innerStyle = useAnimatedStyle(() => {
    const angle = rotationY ? rotationY.value : 0;
    
    // Convert angle to radians for smooth width/height interpolation
    const rad = (angle * Math.PI) / 180;
    const sinSq = Math.sin(rad) * Math.sin(rad);
    const cosSq = Math.cos(rad) * Math.cos(rad);

    // Smoothly interpolate width and height based on the angle
    const currentWidth = screenW * cosSq + screenH * sinSq;
    const currentHeight = screenH * cosSq + screenW * sinSq;

    return {
      width: currentWidth,
      height: currentHeight,
      transform: [{ rotate: `${angle}deg` }],
    };
  });

  return (
    <Animated.View
      style={[
        styles.slotContainer,
        { width: slotWidth, paddingRight: gap },
        outerStyle,
      ]}
    >
      <Animated.View style={zoomStyle}>
        <Animated.View style={innerStyle}>
          <Image
            source={photo.uri}
            placeholder={placeholderUriRef.current}
            style={styles.previewImage}
            contentFit="contain"
            transition={0}
            onLoad={onLoad}
          />
        </Animated.View>
      </Animated.View>
    </Animated.View>
  );
}, (prevProps, nextProps) => {
  return (
    prevProps.index === nextProps.index &&
    prevProps.slotWidth === nextProps.slotWidth &&
    prevProps.gap === nextProps.gap &&
    prevProps.initialUri === nextProps.initialUri &&
    prevProps.photo.id === nextProps.photo.id &&
    prevProps.photo.uri === nextProps.photo.uri &&
    prevProps.onLoad === nextProps.onLoad
  );
});

AnimatedSlot.displayName = 'AnimatedSlot';

const styles = StyleSheet.create({
  slotContainer: {
    position: 'absolute',
    height: '100%',
    justifyContent: 'center', // Prevents shifting off-screen
    alignItems: 'center',     // Prevents shifting off-screen
  },
  previewImage: {
    width: '100%',
    height: '100%',
  },
});

import React, { ReactNode, useMemo } from 'react';
import { StyleSheet, Dimensions, Platform, StatusBar } from 'react-native';
import { GestureDetector, Gesture } from 'react-native-gesture-handler';
import Animated, { useSharedValue, useAnimatedStyle, withTiming, Easing, useAnimatedReaction, SharedValue } from 'react-native-reanimated';
import { useControlPanelStore } from '@entities/system';
import { useShallow } from 'zustand/shallow';
import { useBodyStore } from '@entities/body';
import { useSafeAreaInsets } from 'react-native-safe-area-context';
import { useInteractionContext } from '@shared/lib';

interface GestureControllerProps {
  children?: ReactNode;
  footerTranslateY?: SharedValue<number>;
  drawerAnimation?: SharedValue<number>;
  viewfinderTranslateY?: SharedValue<number>;
}

export const GestureController = React.memo(({ children, footerTranslateY, drawerAnimation, viewfinderTranslateY }: GestureControllerProps) => {
  const { activeSection, setActiveSection } = useControlPanelStore(useShallow((s) => ({
    activeSection: s.activeSection,
    setActiveSection: s.setActiveSection,
  })));

  const { isInteractable } = useInteractionContext();
  const insets = useSafeAreaInsets();
  const { width: screenWidth, height: screenHeight } = Dimensions.get('window');

  const statusBarHeight = Platform.OS === 'android' 
    ? (StatusBar.currentHeight ?? 24) 
    : 47;

  const viewportWidth = screenWidth;
  const viewportHeight = screenHeight - statusBarHeight - 80 - insets.bottom;

  const localTranslateY = useSharedValue(0);
  const translateY = viewfinderTranslateY ?? localTranslateY;
  const startY = useSharedValue(0);
  const hasMoved = useSharedValue(false);
  const hasWarnedPanNaN = useSharedValue(false);

  const isClosing = useSharedValue(false);
  const isPanning = useSharedValue(false);

  const activeSectionSV = useSharedValue(activeSection);

  React.useEffect(() => {
    activeSectionSV.value = activeSection;
  }, [activeSection]);

  const lastTapTime = React.useRef<number>(0);
  const tapTimeout = React.useRef<NodeJS.Timeout | null>(null);

  React.useEffect(() => {
    return () => {
      if (tapTimeout.current) {
        clearTimeout(tapTimeout.current);
      }
    };
  }, []);

  React.useEffect(() => {
    if (activeSection === 'none') {
      isClosing.value = true;
      translateY.value = withTiming(0, { duration: 300 }, (finished) => {
        isClosing.value = false;
        if (activeSectionSV.value === 'none') {
          translateY.value = 0;
        }
      });
    } else {
      isClosing.value = false;
    }
  }, [activeSection, translateY, isClosing, activeSectionSV]);

  const { aspectRatio } = useBodyStore.getState();

  useAnimatedReaction(
    () => {
      return aspectRatio.value;
    },
    (currentValue, previousValue) => {
      if (previousValue !== undefined && previousValue !== null && currentValue !== previousValue) {
        translateY.value = withTiming(0, { duration: 300 });
      }
    }
  );

  const getDynamicLimit = () => {
    'worklet';
    const ft = footerTranslateY ? footerTranslateY.value : 0;
    const da = drawerAnimation ? drawerAnimation.value + 250 : 0;
    if (!footerTranslateY) return 0;

    const aspectValue = aspectRatio.value;
    let targetAspect = 4.0 / 3.0;
    if (aspectValue === 0) targetAspect = 4.0 / 3.0;
    else if (aspectValue === 1) targetAspect = 16.0 / 9.0;
    else if (aspectValue === 2) targetAspect = 1.0;
    else if (aspectValue === 3) targetAspect = 3.0 / 2.0;
    else if (aspectValue === 4) targetAspect = 65.0 / 24.0;

    if (viewportHeight <= 0 || viewportWidth <= 0) {
      const limit = ft + da - 144;
      return limit > 0 ? 0 : limit;
    }

    const viewAspect = viewportWidth / viewportHeight;
    const finalTargetAspect = 1.0 / targetAspect;

    let lBottom = 0;
    if (viewAspect <= finalTargetAspect) {
      const previewHeight = viewportWidth * targetAspect;
      lBottom = (viewportHeight - previewHeight) / 2;
    }

    const limit = ft + da - 144 + lBottom;
    return limit > 0 ? 0 : limit;
  };

  useAnimatedReaction(
    () => {
      // Direct access to ensure Reanimated auto-subscribes to changes
      const ftVal = footerTranslateY ? footerTranslateY.value : 0;
      const daVal = drawerAnimation ? drawerAnimation.value + 250 : 0;
      const aspectVal = aspectRatio.value;
      
      return getDynamicLimit();
    },
    (currentLimit) => {
      if (!isClosing.value && !isPanning.value && footerTranslateY && translateY.value < currentLimit) {
        translateY.value = currentLimit;
      }
    }
  );

  useAnimatedReaction(
    () => {
      return {
        active: activeSectionSV.value,
        closing: isClosing.value,
      };
    },
    (state) => {
      if (state.active === 'none' && !state.closing && translateY.value !== 0) {
        translateY.value = 0;
      }
    }
  );

  useAnimatedReaction(
    () => Math.round(translateY.value),
    (current, prev) => {
      if (prev !== null && Math.abs(current - prev) > 10) {
        console.log(`[GestureController] translateY jumped from ${prev} to ${current}. ActiveSection: ${activeSectionSV.value}, isClosing: ${isClosing.value}`);
      }
    }
  );

  const composedGesture = useMemo(() => {
    const { zoom } = useBodyStore.getState();

    const tap = Gesture.Tap()
      .enabled(isInteractable)
      .runOnJS(true)
      .onBegin(() => {
        hasMoved.value = false;
      })
      .onEnd(() => {
        if (hasMoved.value) {
          return;
        }
        const now = Date.now();
        const zoomVal = zoom.value;
        const isAtOneX = Math.abs(zoomVal - 1.0) < 0.01;

        if (isAtOneX) {
          if (activeSectionSV.value !== 'none') {
            setActiveSection('none');
          }
          return;
        }

        // If not at 1x, check for double tap
        if (now - lastTapTime.current < 200) {
          if (tapTimeout.current) {
            clearTimeout(tapTimeout.current);
            tapTimeout.current = null;
          }
          zoom.value = withTiming(1.0, { duration: 250, easing: Easing.out(Easing.quad) });
          lastTapTime.current = 0; // Reset
        } else {
          lastTapTime.current = now;
          if (tapTimeout.current) {
            clearTimeout(tapTimeout.current);
          }
          tapTimeout.current = setTimeout(() => {
            if (activeSectionSV.value !== 'none') {
              setActiveSection('none');
            }
            tapTimeout.current = null;
          }, 200);
        }
      });

    const pan = Gesture.Pan()
      .enabled(isInteractable)
      .maxPointers(1)
      .onStart(() => {
        isPanning.value = true;
        startY.value = translateY.value;
        hasMoved.value = false;
      })
      .onChange((event) => {
        const cy = event.changeY ?? 0;
        if (isNaN(cy)) {
          if (__DEV__ && !hasWarnedPanNaN.value) {
            hasWarnedPanNaN.value = true;
            console.warn(`[Gesture Warning]: changeY is NaN in GestureController`);
          }
          return;
        }
        if (activeSectionSV.value !== 'none') {
          let newY = translateY.value + cy;
          if (newY > 0) newY = 0;
          
          if (footerTranslateY) {
            const limit = getDynamicLimit();
            if (newY < limit) newY = limit;
          }
          translateY.value = newY;
        }
        if (Math.abs(event.translationY) > 5) {
          hasMoved.value = true;
        }
      })
      .onEnd(() => {
        // The viewfinder remains in its dragged position.
        // No closing of active section, no snap-back here.
      })
      .onFinalize(() => {
        isPanning.value = false;
      });

    return Gesture.Simultaneous(tap, pan);
  }, [setActiveSection, translateY, startY, hasMoved, footerTranslateY, drawerAnimation, viewportWidth, viewportHeight, isInteractable]);

  const animatedStyle = useAnimatedStyle(() => {
    return {
      transform: [{ translateY: translateY.value }],
    };
  });

  return (
    <GestureDetector gesture={composedGesture}>
      <Animated.View style={[styles.container, animatedStyle]} pointerEvents="auto">
        {children}
      </Animated.View>
    </GestureDetector>
  );
});

GestureController.displayName = 'GestureController';

const styles = StyleSheet.create({
  container: {
    position: 'absolute',
    left: 0,
    right: 0,
    top: 0,
    bottom: 0,
    justifyContent: 'center',
    zIndex: 10,
  },
});

import React from 'react';
import { render, act } from '@testing-library/react-native';
import { View, Dimensions } from 'react-native';
import * as reanimated from 'react-native-reanimated';
import { GestureController } from './GestureController';
import { useControlPanelStore } from '@entities/system';
import { Gesture } from 'react-native-gesture-handler';
import { useBodyStore } from '@entities/body';

// Mock the stores
jest.mock('@entities/system', () => ({
  useSystemStore: jest.fn(),
  useControlPanelStore: jest.fn(),
}));

describe('GestureController', () => {
  const mockSetActiveSection = jest.fn();
  let currentActiveSection = 'none';

  let capturedTapGesture: any;
  let capturedPanGesture: any;
  let originalTap: any;
  let originalPan: any;
  let originalSpring: any;
  let originalUseSharedValue: any;
  let originalAnimatedReaction: any;
  let capturedAspectReaction: any;
  let capturedFooterReaction: any;
  let reactionCount = 0;
  let mockTranslateY: any;
  let mockStartY: any;
  let sharedValuesArray: any[] = [];
  let dateNowSpy: any;

  beforeAll(() => {
    originalSpring = reanimated.withSpring;
    originalUseSharedValue = reanimated.useSharedValue;
    originalAnimatedReaction = reanimated.useAnimatedReaction;

    (reanimated as any).withSpring = (value: any, config: any, callback: any) => {
      if (typeof callback === 'function') {
        callback(true);
      }
      return value;
    };

    (reanimated as any).useSharedValue = (initialVal: any) => {
      // eslint-disable-next-line react-hooks/rules-of-hooks
      const ref = React.useRef<any>(null);
      if (!ref.current) {
        ref.current = { value: initialVal };
        sharedValuesArray.push(ref.current);
        if (sharedValuesArray.length === 1) {
          mockTranslateY = ref.current;
        } else if (sharedValuesArray.length === 2) {
          mockStartY = ref.current;
        }
      }
      return ref.current;
    };

    (reanimated as any).useAnimatedReaction = (prepare: any, react: any) => {
      if (reactionCount === 0) {
        capturedAspectReaction = react;
      } else if (reactionCount === 1) {
        capturedFooterReaction = react;
      }
      reactionCount++;
    };
  });

  afterAll(() => {
    (reanimated as any).withSpring = originalSpring;
    (reanimated as any).useSharedValue = originalUseSharedValue;
    (reanimated as any).useAnimatedReaction = originalAnimatedReaction;
  });

  beforeEach(() => {
    jest.clearAllMocks();
    jest.useFakeTimers();
    currentActiveSection = 'none';
    sharedValuesArray = [];
    mockTranslateY = null;
    mockStartY = null;
    capturedAspectReaction = null;
    capturedFooterReaction = null;
    reactionCount = 0;

    (useControlPanelStore as unknown as jest.Mock).mockImplementation((selector?: (state: any) => any) => {
      const state = {
        activeSection: currentActiveSection,
        setActiveSection: mockSetActiveSection,
      };
      return selector ? selector(state) : state;
    });

    capturedTapGesture = null;
    capturedPanGesture = null;
    originalTap = Gesture.Tap;
    originalPan = Gesture.Pan;

    Gesture.Tap = (...args: any[]) => {
      const gesture = originalTap(...args);
      capturedTapGesture = gesture;
      return gesture;
    };

    Gesture.Pan = (...args: any[]) => {
      const gesture = originalPan(...args);
      capturedPanGesture = new Proxy(gesture, {
        get(target, prop) {
          if (prop === '_onChange') {
            const originalOnChange = target[prop];
            if (typeof originalOnChange === 'function') {
              return (event: any) => {
                const eventWithChangeY = {
                  changeY: event && event.changeY !== undefined ? event.changeY : (event ? event.translationY : undefined),
                  ...event,
                };
                return originalOnChange(eventWithChangeY);
              };
            }
          }
          return target[prop];
        }
      });
      return gesture;
    };
  });

  afterEach(() => {
    Gesture.Tap = originalTap;
    Gesture.Pan = originalPan;
    jest.useRealTimers();
    if (dateNowSpy) {
      dateNowSpy.mockRestore();
    }
  });

  it('should render children correctly', () => {
    const { getByTestId } = render(
      <GestureController>
        <View testID="test-child" />
      </GestureController>
    );
    expect(getByTestId('test-child')).toBeDefined();
  });

  it('handles Tap gesture to close active section instantly when zoom is 1.0', () => {
    currentActiveSection = 'lens';
    const bodyStore = useBodyStore.getState();
    bodyStore.zoom.value = 1.0;

    render(<GestureController />);

    expect(capturedTapGesture).toBeDefined();

    act(() => {
      capturedTapGesture._onEnd();
    });

    expect(mockSetActiveSection).toHaveBeenCalledWith('none');
  });

  it('does not close section on Tap gesture if activeSection is none', () => {
    currentActiveSection = 'none';
    const bodyStore = useBodyStore.getState();
    bodyStore.zoom.value = 1.0;

    render(<GestureController />);

    act(() => {
      capturedTapGesture._onEnd();
    });

    expect(mockSetActiveSection).not.toHaveBeenCalled();
  });

  it('handles Tap gesture to close active section after delay when zoom is not 1.0', () => {
    currentActiveSection = 'lens';
